"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[3468],{5169:(s,n,a)=>{a.r(n),a.d(n,{data:()=>e});const e={key:"v-360fe945",path:"/knowledge/Deepin/%E5%9C%A8Deepin%E6%A1%8C%E9%9D%A2%E5%88%9B%E5%BB%BA%E7%A8%8B%E5%BA%8F%E5%9B%BE%E6%A0%87.html",title:"「Linux」在Deepin桌面创建程序图标(快捷方式)",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"首先在桌面按下Ctrl+Alt+T调出终端,输入",slug:"首先在桌面按下ctrl-alt-t调出终端-输入",children:[]},{level:2,title:"这时桌面会生成一个desktop文件，",slug:"这时桌面会生成一个desktop文件",children:[]},{level:2,title:"Categories参数",slug:"categories参数",children:[]},{level:2,title:"接着在桌面打开终端，输入",slug:"接着在桌面打开终端-输入",children:[]},{level:2,title:"以下是几个图标的例子：",slug:"以下是几个图标的例子",children:[]},{level:2,title:"保存之后，便可以在列表看见启动图标",slug:"保存之后-便可以在列表看见启动图标",children:[]}],filePathRelative:"knowledge/Deepin/在Deepin桌面创建程序图标.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},510:(s,n,a)=>{a.r(n),a.d(n,{default:()=>l});const e=(0,a(6252).uE)('<h1 id="「linux」在deepin桌面创建程序图标-快捷方式" tabindex="-1"><a class="header-anchor" href="#「linux」在deepin桌面创建程序图标-快捷方式" aria-hidden="true">#</a> 「Linux」在Deepin桌面创建程序图标(快捷方式)</h1><p>在<code>Linux</code>系统中经常有些程序没有安装程序，下载解压后就可以使用了，这样是特别方便的，但是同样是因为这样，也造成每次打开程序找到对应文件才能执行，因此在图形化的桌面创建一个快捷方式是有必要的。</p><p>在<code>Deepin</code>和<code>ubuntu</code>系统中桌面图标一般保存在<code>/usr/share/applications/</code>目录中，所以在此处创建<code>.desktop</code>文件即可在启动台中查看到对应图标。</p><h2 id="首先在桌面按下ctrl-alt-t调出终端-输入" tabindex="-1"><a class="header-anchor" href="#首先在桌面按下ctrl-alt-t调出终端-输入" aria-hidden="true">#</a> 首先在桌面按下Ctrl+Alt+T调出终端,输入</h2><p>sudo touch 应用名字.desktop //创建</p><h2 id="这时桌面会生成一个desktop文件" tabindex="-1"><a class="header-anchor" href="#这时桌面会生成一个desktop文件" aria-hidden="true">#</a> 这时桌面会生成一个desktop文件，</h2><p>用记事本打开该文件， 输入以下代码并保存</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token punctuation">[</span>Desktop Entry<span class="token punctuation">]</span>\n<span class="token assign-left variable">Encoding</span><span class="token operator">=</span>UTF-8\n<span class="token assign-left variable">Categories</span><span class="token operator">=</span>Development //类型\n<span class="token assign-left variable">Name</span><span class="token operator">=</span>idea //快捷方式的名称\n<span class="token assign-left variable">Exec</span><span class="token operator">=</span>sh /home/red/软件/ideaIU-2020.3/idea-IU-203.5981.155/bin/idea.sh //你的.sh的完整路径<span class="token punctuation">(</span>*前面的sh不能删<span class="token punctuation">)</span>\n<span class="token assign-left variable">Icon</span><span class="token operator">=</span>/home/red/软件/ideaIU-2020.3/idea-IU-203.5981.155/bin/idea.png//你的快捷方式图片的路径\n<span class="token assign-left variable">Info</span><span class="token operator">=</span><span class="token string">&quot;Spark&quot;</span>\n<span class="token assign-left variable">Terminal</span><span class="token operator">=</span>false\n<span class="token assign-left variable">Type</span><span class="token operator">=</span>Application\n<span class="token assign-left variable">StartupNotify</span><span class="token operator">=</span>true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="categories参数" tabindex="-1"><a class="header-anchor" href="#categories参数" aria-hidden="true">#</a> Categories参数</h2><ol><li>Web Browser//网络应用</li><li>chat//社交沟通</li><li>AudioVideo;Player;//视频播放</li><li>Graphics;2DGraphics;RasterGraphics;GTK;//图形图像</li><li>Game;//游戏</li><li>Office;WordProcessor;//办公学习</li><li>Development;//编程开发</li><li>System;//系统管理</li><li>不写//其他应用</li></ol><h2 id="接着在桌面打开终端-输入" tabindex="-1"><a class="header-anchor" href="#接着在桌面打开终端-输入" aria-hidden="true">#</a> 接着在桌面打开终端，输入</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">mv</span> 应用名字.desktop /usr/share/applications/\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>自此快捷方式就成功添加到软件列表了</p><h2 id="以下是几个图标的例子" tabindex="-1"><a class="header-anchor" href="#以下是几个图标的例子" aria-hidden="true">#</a> 以下是几个图标的例子：</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>\n<span class="token punctuation">[</span>Desktop Entry<span class="token punctuation">]</span>\n<span class="token assign-left variable">Type</span><span class="token operator">=</span>Application    //定义了Desktop Entry文件的类型\n<span class="token assign-left variable">Version</span><span class="token operator">=</span><span class="token number">1.0</span>    //<span class="token punctuation">[</span>可选<span class="token punctuation">]</span> 该数值指定了当前 Desktop Entry 文件所遵循的 Desktop Entry 文件标准版本.\n<span class="token assign-left variable">Name</span><span class="token operator">=</span>eclipse-jee    //应用程序名称\n<span class="token assign-left variable">Comment</span><span class="token operator">=</span>eclipse <span class="token keyword">for</span> jee    //对当前程序的简单描述\n<span class="token assign-left variable">Exec</span><span class="token operator">=</span>/opt/apps/org.eclipse.java-ee/files/share/eclipse-jee/eclipse    //程序所在的绝对路径,关键字<span class="token string">&quot;Exec&quot;</span>只有在<span class="token string">&quot;Type&quot;</span>类型是<span class="token string">&quot;Application&quot;</span>时才有意义\n<span class="token assign-left variable">Icon</span><span class="token operator">=</span>eclipse-jee    //程序图标 如果关键字<span class="token string">&quot;Icon&quot;</span>的数值是以绝对路径的格式给出 那么其数值所指定图标文件将被使用 反之,Linux系统将使用<span class="token string">&quot;Icon Theme Specification&quot;</span><span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span>在系统指定图标目录下定位所需要使用的图标文件\n<span class="token assign-left variable">Terminal</span><span class="token operator">=</span>false    //是否需要在终端程序中运行\n<span class="token assign-left variable">Categories</span><span class="token operator">=</span>Development<span class="token punctuation">;</span>IDE<span class="token punctuation">;</span>    //相关应用程序在菜单中显示的类别\n<span class="token assign-left variable">StartupNotify</span><span class="token operator">=</span>true    //<span class="token punctuation">[</span>可选<span class="token punctuation">]</span>该关键字只有在<span class="token string">&quot;Type&quot;</span>类型是<span class="token string">&quot;Application&quot;</span>时才有意义\n\n<span class="token comment"># webstorm</span>\n<span class="token punctuation">[</span>Desktop Entry<span class="token punctuation">]</span>\n<span class="token assign-left variable">Categories</span><span class="token operator">=</span>Development<span class="token punctuation">;</span>IDE<span class="token punctuation">;</span>\n<span class="token assign-left variable">Comment</span><span class="token operator">=</span>webstorm\n<span class="token assign-left variable">Version</span><span class="token operator">=</span><span class="token number">4.1</span>.0\n<span class="token assign-left variable">Encoding</span><span class="token operator">=</span>UTF-8\n<span class="token assign-left variable">Exec</span><span class="token operator">=</span>/usr/webstorm/WebStorm-213.7172.31/bin/webstorm.sh\n<span class="token assign-left variable">Icon</span><span class="token operator">=</span>/usr/webstorm/WebStorm-213.7172.31/bin/webstorm.svg\n<span class="token assign-left variable">MimeType</span><span class="token operator">=</span>\n<span class="token assign-left variable">Name</span><span class="token operator">=</span>WebStorm\n<span class="token assign-left variable">StartupWMClass</span><span class="token operator">=</span>WebStorm\n<span class="token assign-left variable">Terminal</span><span class="token operator">=</span>false\n<span class="token assign-left variable">Type</span><span class="token operator">=</span>Application\n\n<span class="token comment"># PyCharm</span>\n<span class="token punctuation">[</span>Desktop Entry<span class="token punctuation">]</span>\n<span class="token assign-left variable">Name</span><span class="token operator">=</span>Pycharm-2020\n<span class="token assign-left variable">Type</span><span class="token operator">=</span>Application\n<span class="token assign-left variable">Exec</span><span class="token operator">=</span>/home/sul/Downloads/pycharm-2020.1/bin/pycharm.sh\n<span class="token assign-left variable">Terminal</span><span class="token operator">=</span>false\n<span class="token assign-left variable">Icon</span><span class="token operator">=</span>/home/sul/Downloads/pycharm-2020.1/bin/pycharm.svg\n<span class="token assign-left variable">Comment</span><span class="token operator">=</span>Integrated Development Environment\n<span class="token assign-left variable">NoDisplay</span><span class="token operator">=</span>false\n<span class="token assign-left variable">Categories</span><span class="token operator">=</span>Development<span class="token punctuation">;</span>IDE<span class="token punctuation">;</span>\nName<span class="token punctuation">[</span>en<span class="token punctuation">]</span><span class="token operator">=</span>pycharm-2020\n\n<span class="token comment"># deepin-qq</span>\n<span class="token comment">#!/usr/bin/env xdg-open</span>\n<span class="token punctuation">[</span>Desktop Entry<span class="token punctuation">]</span>\n<span class="token assign-left variable">Encoding</span><span class="token operator">=</span>UTF-8\n<span class="token assign-left variable">Type</span><span class="token operator">=</span>Application\nX-Created-By<span class="token operator">=</span>Deepin WINE Team\n<span class="token assign-left variable">Categories</span><span class="token operator">=</span>chat<span class="token punctuation">;</span>\n<span class="token assign-left variable">Icon</span><span class="token operator">=</span>com.qq.im.deepin\n<span class="token assign-left variable">Exec</span><span class="token operator">=</span><span class="token string">&quot;/opt/apps/com.qq.im.deepin/files/run.sh&quot;</span> -u %u\n<span class="token assign-left variable">Name</span><span class="token operator">=</span>QQ\nName<span class="token punctuation">[</span>zh_CN<span class="token punctuation">]</span><span class="token operator">=</span>QQ\n<span class="token assign-left variable">Comment</span><span class="token operator">=</span>Tencent QQ Client on Deepin Wine\n<span class="token assign-left variable">StartupWMClass</span><span class="token operator">=</span>QQ.exe\n<span class="token assign-left variable">MimeType</span><span class="token operator">=</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br></div></div><h1 id="以上是几个图标的例子" tabindex="-1"><a class="header-anchor" href="#以上是几个图标的例子" aria-hidden="true">#</a> 以上是几个图标的例子</h1><h2 id="保存之后-便可以在列表看见启动图标" tabindex="-1"><a class="header-anchor" href="#保存之后-便可以在列表看见启动图标" aria-hidden="true">#</a> 保存之后，便可以在列表看见启动图标</h2><p>一般对于.desktop文件来说至少需要包含：</p><ul><li>Name</li><li>Type</li><li>Exec</li><li>Terminal</li><li>Icon</li><li>Categories</li><li>Comment</li></ul>',19),p={},l=(0,a(3744).Z)(p,[["render",function(s,n){return e}]])},3744:(s,n)=>{n.Z=(s,n)=>{const a=s.__vccOpts||s;for(const[s,e]of n)a[s]=e;return a}}}]);